CREATE INDEX IF NOT EXISTS idx_hexagrams_category ON hexagrams_64(category);
CREATE INDEX IF NOT EXISTS idx_hexagrams_upper ON hexagrams_64(upper_trigram);
CREATE INDEX IF NOT EXISTS idx_hexagrams_lower ON hexagrams_64(lower_trigram);

